input.function:
() => {
  const panel = document.querySelector('#history');
  if (!panel) return { error: 'history panel not found' };
  const links = Array.from(panel.querySelectorAll('a[href*="/project/requests/"]'));
  const entries = links
    .map(a => {
      const p = a.querySelector('p');
      const versionText = p ? p.textContent.trim() : a.textContent.trim().split(/\s+/)[0];
      const timeEl = a.querySelector('time');
      const dateText = timeEl ? timeEl.textContent.trim() : '';
      return { versionText, dateText };
    })
    .filter(e => /^\d/.test(e.versionText));

  const isPre = (v) => /(?:a|b|rc|dev)\d*/i.test(v);
  const stableEntries = entries.filter(e => !isPre(e.versionText));

  return {
    total: entries.length,
    latestListed: entries[0] || null,
    oldestListed: entries[entries.length - 1] || null,
    latestStable: stableEntries[0] || null
  };
}

